@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "GET":
        return render_template_string(LOGIN_TEMPLATE, error=None)

    username = request.form.get("username", "").strip()
    password = request.form.get("password", "")

    user = USERS.get(username)
    if not user or not verify_password(user["password_hash"], password):
        return render_template_string(LOGIN_TEMPLATE, error="Invalid username or password"), 401

    if user["mfa_enabled"]:
        challenge_id = secrets.token_urlsafe(32)
        PENDING_MFA[challenge_id] = {
            "username": username,
            "created_at": time.time(),
        }
        session["pending_mfa_id"] = challenge_id
        return render_template_string(OTP_TEMPLATE, error=None)

    session["authenticated"] = True
    session["username"] = username
    return redirect(url_for("home"))

@app.route("/verify-otp", methods=["POST"])
def verify_otp():
    challenge_id = session.get("pending_mfa_id")
    if not challenge_id or challenge_id not in PENDING_MFA:
        return render_template_string(LOGIN_TEMPLATE, error="MFA session expired. Please log in again."), 401

    challenge = PENDING_MFA[challenge_id]
    username = challenge["username"]
    user = USERS.get(username)
    if not user or not user["mfa_enabled"]:
        PENDING_MFA.pop(challenge_id, None)
        session.pop("pending_mfa_id", None)
        return render_template_string(LOGIN_TEMPLATE, error="Invalid MFA state."), 401

    otp = request.form.get("otp", "").strip()
    if not otp:
        return render_template_string(OTP_TEMPLATE, error="OTP is required."), 400

    current_counter = int(time.time() // 30)
    valid = False
    for offset in (-1, 0, 1):
        if hotp(user["mfa_secret"], current_counter + offset) == otp:
            valid = True
            break

    if not valid:
        return render_template_string(OTP_TEMPLATE, error="Invalid OTP."), 401

    PENDING_MFA.pop(challenge_id, None)
    session.pop("pending_mfa_id", None)
    session["authenticated"] = True
    session["username"] = username
    return redirect(url_for("home"))

@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("login"))

@app.route("/api/login", methods=["POST"])
def api_login():
    data = request.get_json(silent=True) or request.form
    username = data.get("username", "").strip()
    password = data.get("password", "")

    user = USERS.get(username)
    if not user or not verify_password(user["password_hash"], password):
        return jsonify({"success": False, "error": "Invalid username or password"}), 401

    if user["mfa_enabled"]:
        return jsonify({"success": False, "mfa_required": True, "message": "MFA required"}), 200

    token = secrets.token_urlsafe(32)
    return jsonify({"success": True, "token": token, "mfa_required": False}), 200

@app.route("/api/direct-login", methods=["POST"])
def api_direct_login():
    data = request.get_json(silent=True) or request.form
